from typing import List

class Solution:
    def maxTotalAccuracy(self, N: int, T: int, accuracy: List[int], latency: List[int]) -> int:
        # dp[i][t] 表示完成 i 次查询且恰好用时 t 时的最大准确率
        dp = [[-1] * (T + 1) for _ in range(N + 1)]
        dp[0][0] = 0

        for i in range(1, N + 1):
            for t in range(T + 1):
                for j in range(len(accuracy)):
                    cost = latency[j]

                    # 当前时间足够，且上一个状态可达
                    if t >= cost and dp[i - 1][t - cost] != -1:
                        dp[i][t] = max(
                            dp[i][t],
                            dp[i - 1][t - cost] + accuracy[j]
                        )

        ans = max(dp[N])

        # 如果无法查满 N 次，返回 0
        return ans if ans != -1 else 0

```


```java
class Solution {
    public int maxTotalAccuracy(int N, int T, int[] accuracy, int[] latency) {
        int m = accuracy.length;

        // dp[i][t] 表示完成 i 次查询，恰好花费 t 时间时的最大准确率
        int[][] dp = new int[N + 1][T + 1];

        // 初始化为不可达
        for (int i = 0; i <= N; i++) {
            for (int t = 0; t <= T; t++) {
                dp[i][t] = -1;
            }
        }

        dp[0][0] = 0;

        // 枚举查询次数
        for (int i = 1; i <= N; i++) {
            // 枚举当前总耗时
            for (int t = 0; t <= T; t++) {
                // 枚举选择的模型
                for (int j = 0; j < m; j++) {
                    int cost = latency[j];
                    int value = accuracy[j];

                    // 如果当前时间足够，并且上一个状态可达
                    if (t >= cost && dp[i - 1][t - cost] != -1) {
                        dp[i][t] = Math.max(dp[i][t], dp[i - 1][t - cost] + value);
                    }
                }
            }
        }

        // 总耗时不超过 T，取完成 N 次查询的最大值
        int ans = -1;
        for (int t = 0; t <= T; t++) {
            ans = Math.max(ans, dp[N][t]);
        }

        return ans == -1 ? 0 : ans;
    }
}
```

