        // 枚举当前总耗时
        for (int t = 0; t <= T; t++) {
            // 枚举选择的模型
            for (int j = 0; j < accuracySize; j++) {
                int cost = latency[j];
                int value = accuracy[j];
                // 当前时间足够，且上一个状态可达
                if (t >= cost && dp[i - 1][t - cost] != -1) {
                    int candidate = dp[i - 1][t - cost] + value;
                    if (candidate > dp[i][t])
                        dp[i][t] = candidate;
                }
            }
        }
    }

    // 在总耗时不超过 T 的前提下，取完成 N 次查询的最大值
    int ans = -1;
    for (int t = 0; t <= T; t++)
        if (dp[N][t] > ans)
            ans = dp[N][t];

